import { Component, OnInit } from "@angular/core";
import { DatePipe, formatNumber } from "@angular/common";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { AlertService } from "src/app/core/services/alert.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { ITransType } from "src/app/views/Models/References/TransactionsType";
@Component({
  selector: "app-transaction-type",
  templateUrl: "./transaction-type.page.html",
  styleUrls: ["./transaction-type.page.scss"],
})
export class TransactionTypePage implements OnInit {
  [x: string]: any;
  transType: StaticRef[];
  AccountType: StaticRef[];
  TransReference: StaticRef[];
  TransTypeForm: FormGroup = this.formBuilder.group({
    type_key: [""],
    trans_act_desc: ["", [Validators.required]],
    trans_type: ["", [Validators.required]],
    account_type: ["", [Validators.required]],
    active_rec: [0],
    allow_client_trans_on_vac: [0],
    trans_reference: ["", [Validators.required]],
    sales_tax: ["0", [Validators.required]],
  });
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

  constructor(
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    private http: HttpClient,
    private env: EnvService,
    private alertServices: AlertService,
    private ReferencesService: ReferencesService
  ) {}
  showLoader: boolean = false;
  TransType: ITransType[];
  isSubmitted: boolean = false;
  isInserting: boolean = false;
  isUpdating: boolean = false;

  ngOnInit() {
    this.transaction();
  }
  async transaction() {
    this.TransType = await this.ReferencesService.GetTransAll();
    console.log(this.TransType, "1111111");
    this.transType = await this.ReferencesService.GetTransType();
    this.AccountType = await this.ReferencesService.GetAccountType();
    this.TransReference = await this.ReferencesService.GetTransReference();
  }
  clearForms() {
    this.isInserting = false;
    this.isUpdating = false;
    this.isSubmitted = false;
    this.TransTypeForm.reset();
  }
  updateTransType(index: number) {
    const TransType = this.TransType[index];
    this.TransTypeForm.patchValue({
      type_key: TransType.type_key,
      trans_act_desc: TransType.trans_act_desc,
      trans_type: TransType.trans_type.toString(),
      account_type: TransType.account_type.toString(),
      active_rec: TransType.active_rec == "1",
      allow_client_trans_on_vac: TransType.allow_client_trans_on_vac == "1",
      trans_reference: TransType.trans_reference
        ? TransType.trans_reference.toString()
        : null,
      sales_tax: TransType.sales_tax,
    });
    this.isInserting = false;
    this.isUpdating = true;
  }
  async insertTransType() {
    this.isUpdating = false;
    this.isInserting = true;
  }
  async deleteTransType(type_key: string) {
    await this.ReferencesService.GetTransTypeDelete(type_key.toString());
    this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
  }
  async submitTransInsert() {
    try {
      if (this.TransTypeForm.valid) {
        await this.ReferencesService.GetTransTypeInsert(
          this.TransTypeForm.value.trans_act_desc,
          this.TransTypeForm.value.trans_type,
          this.TransTypeForm.value.account_type,
          this.TransTypeForm.value.active_rec === true ? 1 : 0,
          this.TransTypeForm.value.allow_client_trans_on_vac === true ? 1 : 0,
          this.TransTypeForm.value.trans_reference,
          this.TransTypeForm.value.sales_tax
        );
        this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
      } else {
        this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
      }
    } catch {}
  }
  async submitTransUpdate() {
    try {
      if (this.TransTypeForm.valid) {
        await this.ReferencesService.GetTransTypeUpdate(
          this.TransTypeForm.value.type_key,
          this.TransTypeForm.value.trans_act_desc,
          this.TransTypeForm.value.trans_type,
          this.TransTypeForm.value.account_type,
          this.TransTypeForm.value.active_rec === true ? 1 : 0,
          this.TransTypeForm.value.allow_client_trans_on_vac === true ? 1 : 0,
          this.TransTypeForm.value.trans_reference,
          this.TransTypeForm.value.sales_tax
        );
        this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
      } else {
        this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
      }
    } catch {}
  }
}
